 727→private func plainTextPreview(from html: String) -> String {
 728→    var text = html.replacingOccurrences(of: "<[^>]+>", with: " ", options: .regularExpression)
 729→    text = text.replacingOccurrences(of: "&nbsp;", with: " ")
 730→    text = text.replacingOccurrences(of: "&amp;", with: "&")
 731→    text = text.replacingOccurrences(of: "&lt;", with: "<")
 732→    text = text.replacingOccurrences(of: "&gt;", with: ">")
 733→    text = text.replacingOccurrences(of: "&quot;", with: "\"")
 734→    text = text.replacingOccurrences(of: "&#39;", with: "'")
 735→    text = text.replacingOccurrences(of: "\\s+", with: " ", options: .regularExpression)
 736→    return text.trimmingCharacters(in: .whitespacesAndNewlines)
 737→}
