1169→    private func toggleReaction(emoji: String) async {
1170→        guard !isReacting else { return }
1171→        guard AuthManager.shared.currentAccount != nil else {
1172→            reactionErrorMessage = ReactionL10n.signInRequired
1173→            return
1174→        }
1175→        isReacting = true
1176→        defer { isReacting = false }
1177→
1178→        let shouldRemove = reactionGroups.first(where: { $0.emoji == emoji })?.viewerHasReacted == true
1179→
1180→        do {
1181→            if shouldRemove {
1182→                let response = try await apolloClient.perform(
1183→                    mutation: HackersPub.RemoveReactionFromPostMutation(postId: post.id, emoji: emoji)
1184→                )
1185→
1186→                if let payload = response.data?.removeReactionFromPost.asRemoveReactionFromPostPayload, payload.success {
1187→                    applyReactionLocally(emoji: emoji, add: false)
1188→                } else {
1189→                    reactionErrorMessage = ReactionL10n.unableToRemove
1190→                }
1191→            } else {
1192→                let response = try await apolloClient.perform(
1193→                    mutation: HackersPub.AddReactionToPostMutation(postId: post.id, emoji: emoji)
1194→                )
1195→
1196→                if let payload = response.data?.addReactionToPost.asAddReactionToPostPayload, payload.reaction != nil {
1197→                    applyReactionLocally(emoji: emoji, add: true)
1198→                } else {
1199→                    reactionErrorMessage = ReactionL10n.unableToAdd
1200→                }
1201→            }
1202→        } catch {
1203→            reactionErrorMessage = shouldRemove ? ReactionL10n.unableToRemove : ReactionL10n.unableToAdd
1204→            print("Error toggling reaction: \(error)")
1205→        }
1206→    }
