  5→class FontSettingsManager: ObservableObject {
  6→    static let shared = FontSettingsManager()
  7→
  8→    // User preferences stored in UserDefaults with manual publishing
  9→    @Published var selectedFontName: String {
 10→        didSet {
 11→            UserDefaults.standard.set(selectedFontName, forKey: "selectedFontName")
 12→        }
 13→    }
 14→
 15→    @Published var fontSizeMultiplier: Double {
 16→        didSet {
 17→            UserDefaults.standard.set(fontSizeMultiplier, forKey: "fontSizeMultiplier")
 18→        }
 19→    }
 20→
 21→    @Published var useSystemDynamicType: Bool {
 22→        didSet {
 23→            UserDefaults.standard.set(useSystemDynamicType, forKey: "useSystemDynamicType")
 24→        }
 25→    }
 26→
 27→    private(set) var commonFonts: [String] = []
 28→    private(set) var allAvailableFonts: [String] = []
 29→
 30→    private init() {
 31→        // Load saved preferences
 32→        self.selectedFontName = UserDefaults.standard.string(forKey: "selectedFontName") ?? "System"
 33→        self.fontSizeMultiplier = UserDefaults.standard.double(forKey: "fontSizeMultiplier") != 0 ? UserDefaults.standard.double(forKey: "fontSizeMultiplier") : 1.0
 34→        self.useSystemDynamicType = UserDefaults.standard.object(forKey: "useSystemDynamicType") as? Bool ?? true
 35→
 36→        loadAllAvailableFonts()
 37→        setupCommonFonts()
 38→    }
 39→
 40→    // Load all fonts available on the device
 41→    private func loadAllAvailableFonts() {
 42→        var families = Set<String>()
 43→        var allFonts = Set<String>()
 44→
 45→        // Always include System as the first option
 46→        allFonts.insert("System")
 47→
 48→        for familyName in UIFont.familyNames.sorted() {
 49→            families.insert(familyName)
 50→            let fontNames = UIFont.fontNames(forFamilyName: familyName)
 51→            for fontName in fontNames {
 52→                allFonts.insert(fontName)
 53→            }
 54→        }
 55→
 56→        allAvailableFonts = Array(allFonts).sorted { font1, font2 in
 57→            if font1 == "System" { return true }
 58→            if font2 == "System" { return false }
 59→            return font1.localizedCaseInsensitiveCompare(font2) == .orderedAscending
 60→        }
 61→    }
 62→
 63→    // Setup common fonts from detected fonts
 64→    private func setupCommonFonts() {
 65→        // List of commonly used font families (will be filtered by what's actually available)
 66→        let commonFamilyNames = [
 67→            "System",
 68→            "New York",
 69→            "Arial",
 70→            "Helvetica",
 71→            "Helvetica Neue",
 72→            "Times New Roman",
 73→            "Courier",
 74→            "Courier New",
 75→            "Avenir",
 76→            "Avenir Next",
 77→        ]
 78→
 79→        var common = [String]()
 80→
 81→        for fontName in commonFamilyNames {
 82→            if fontName == "System" || isFontAvailable(fontName) {
 83→                common.append(fontName)
 84→            }
 85→        }
 86→
 87→        commonFonts = common
 88→    }
 89→
 90→    // Get font name for CSS
 91→    var cssFontFamily: String {
 92→        switch selectedFontName {
 93→        case "System":
 94→            return "-apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif"
 95→
 96→        default:
 97→            // For custom fonts, wrap in quotes and provide fallback
 98→            return "'\(selectedFontName)', -apple-system, sans-serif"
 99→        }
100→    }
101→
102→    func uiFont(for textStyle: UIFont.TextStyle, weight: UIFont.Weight = .regular) -> UIFont {
103→        let size = scaledSize(for: textStyle)
104→
105→        if selectedFontName == "System" {
106→            return UIFont.systemFont(ofSize: size, weight: weight)
107→        }
108→
109→        if let font = UIFont(name: selectedFontName, size: size) {
110→            return font
111→        }
112→
113→        // Fallback to system font
114→        return UIFont.systemFont(ofSize: size, weight: weight)
115→    }
116→
117→    func font(for textStyle: UIFont.TextStyle) -> Font {
118→        let size = scaledSize(for: textStyle)
119→
120→        if selectedFontName == "System" {
121→            return .system(size: size)
122→        }
123→
124→        return .custom(selectedFontName, size: size)
125→    }
126→
127→    // Get scaled font size based on user preference
128→    func scaledSize(for textStyle: UIFont.TextStyle) -> CGFloat {
129→        if useSystemDynamicType {
130→            // Disable multipling font size
131→            return UIFont.preferredFont(forTextStyle: textStyle).pointSize
132→        } else {
133→            // Base sizes when not using dynamic type
134→            let baseSize: CGFloat = {
135→                switch textStyle {
136→                case .largeTitle: return 34
137→                case .title1: return 28
138→                case .title2: return 22
139→                case .title3: return 20
140→                case .headline: return 17
141→                case .body: return 17
142→                case .callout: return 16
143→                case .subheadline: return 15
144→                case .footnote: return 13
145→                case .caption1: return 12
146→                case .caption2: return 11
147→                default: return 17
148→                }
149→            }()
150→            return baseSize * fontSizeMultiplier
151→        }
152→    }
153→
154→    func searchFonts(query: String) -> [String] {
155→        if query.isEmpty {
156→            return commonFonts
157→        }
158→        return allAvailableFonts.filter { $0.localizedCaseInsensitiveContains(query) }
159→    }
160→
161→    func isFontAvailable(_ fontName: String) -> Bool {
162→        if fontName == "System" { return true }
163→        return UIFont(name: fontName, size: 12) != nil
164→    }
165→
166→    func resetToDefaults() {
167→        selectedFontName = "System"
168→        fontSizeMultiplier = 1.0
169→        useSystemDynamicType = true
170→    }
171→}
