640→                    systemImage: "exclamationmark.triangle",
641→                    description: Text(error)
642→                )
643→            } else if let actor = actor {
644→                ActorProfileView(actor: actor)
645→            }
646→        }
647→        .task {
648→            await fetchProfile()
649→        }
650→    }
