652→    private func fetchProfile() async {
653→        isLoading = true
654→        defer { isLoading = false }
655→
656→        do {
657→            // Always fetch from network to get fresh data
658→            let response = try await apolloClient.fetch(query: HackersPub.ActorByHandleQuery(handle: handle, after: nil), cachePolicy: .networkOnly)
