 79→                        .buttonStyle(.borderedProminent)
 80→                        .disabled(verificationCode.isEmpty || isLoading)
 81→
 82→                        Button(NSLocalizedString("signIn.useDifferentUsername", comment: "Use different username button")) {
 83→                            loginState = .enterUsername
 84→                            verificationCode = ""
 85→                            loginToken = nil
 86→                        }
 87→                        .foregroundStyle(.secondary)
 88→                    }
 89→                }
