 29→struct ReactionGroupSnapshot: Identifiable, Hashable {
 30→    let id: String
 31→    let emoji: String?
 32→    let customEmojiName: String?
 33→    let customEmojiImageUrl: String?
 34→    var totalCount: Int
 35→    var viewerHasReacted: Bool
 36→}
 37→
 38→protocol ReactionCapablePostProtocol {
 39→    var reactionGroupsSnapshot: [ReactionGroupSnapshot] { get }
 40→}
 41→
 42→private func sortReactionGroups(_ groups: [ReactionGroupSnapshot]) -> [ReactionGroupSnapshot] {
 43→    let emojiOrder = Dictionary(uniqueKeysWithValues: supportedReactionEmojis.enumerated().map { ($1, $0) })
 44→    return groups.sorted { lhs, rhs in
 45→        switch (lhs.emoji, rhs.emoji) {
 46→        case let (.some(leftEmoji), .some(rightEmoji)):
 47→            let leftIndex = emojiOrder[leftEmoji] ?? Int.max
 48→            let rightIndex = emojiOrder[rightEmoji] ?? Int.max
 49→            if leftIndex != rightIndex {
 50→                return leftIndex < rightIndex
 51→            }
 52→            return leftEmoji < rightEmoji
 53→        case (.some, .none):
 54→            return true
 55→        case (.none, .some):
 56→            return false
 57→        case (.none, .none):
 58→            return (lhs.customEmojiName ?? "") < (rhs.customEmojiName ?? "")
 59→        }
 60→    }
 61→}
